import React, { useState, useEffect, useRef } from 'react';

const API = 'http://localhost:8000';

const nav = ['Dashboard', 'Ingest', 'Meetings', 'Escalations', 'Action Items', 'Risks', 'Query'];
const navIcons = { Dashboard: '📊', Ingest: '⚡', Meetings: '📅', Escalations: '🚨', 'Action Items': '✅', Risks: '⚠️', Query: '🔍' };

export default function App() {
  const [page, setPage] = useState('Ingest');
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    fetch(`${API}/`).then(r => r.ok ? setConnected(true) : setConnected(false)).catch(() => setConnected(false));
  }, []);

  return (
    <div style={{ minHeight: '100vh', background: '#0f1117', color: '#e2e8f0', fontFamily: 'Inter, sans-serif' }}>
      {/* Navbar */}
      <div style={{ background: '#1a1d2e', borderBottom: '1px solid #2d3748', padding: '0 24px', display: 'flex', alignItems: 'center', gap: 32 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '14px 0', marginRight: 16 }}>
          <span style={{ fontSize: 22 }}>🧠</span>
          <span style={{ fontWeight: 700, fontSize: 15, color: '#a78bfa' }}>MeetingIQ</span>
          <span style={{ fontSize: 11, color: '#64748b', marginLeft: 4 }}>INTELLIGENCE SYSTEM</span>
        </div>
        {nav.map(n => (
          <button key={n} onClick={() => setPage(n)} style={{
            background: 'none', border: 'none', cursor: 'pointer', padding: '16px 4px',
            color: page === n ? '#a78bfa' : '#94a3b8', fontWeight: page === n ? 600 : 400,
            borderBottom: page === n ? '2px solid #a78bfa' : '2px solid transparent', fontSize: 14
          }}>
            {navIcons[n]} {n}
          </button>
        ))}
        <div style={{ marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: 6, fontSize: 13 }}>
          <span style={{ width: 8, height: 8, borderRadius: '50%', background: connected ? '#22c55e' : '#ef4444', display: 'inline-block' }} />
          <span style={{ color: connected ? '#22c55e' : '#ef4444' }}>{connected ? 'Connected' : 'Disconnected'}</span>
        </div>
      </div>

      {/* Pages */}
      <div style={{ padding: 32 }}>
        {page === 'Dashboard'    && <Dashboard />}
        {page === 'Ingest'       && <Ingest />}
        {page === 'Meetings'     && <Meetings />}
        {page === 'Escalations'  && <EscalationsPage />}
        {page === 'Action Items' && <ActionItemsPage />}
        {page === 'Risks'        && <RisksPage />}
        {page === 'Query'        && <QueryPage />}
      </div>
    </div>
  );
}

// ─── Dashboard ────────────────────────────────────────────────────────────────
function Dashboard() {
  const [data, setData] = useState(null);
  useEffect(() => { fetch(`${API}/api/dashboard`).then(r => r.json()).then(setData); }, []);
  if (!data) return <Loader />;

  const cards = [
    { label: 'Total Meetings',        value: data.total_meetings,        color: '#6366f1' },
    { label: 'Open Escalations',      value: data.open_escalations,      color: '#ef4444' },
    { label: 'Active Blockers',       value: data.active_blockers,       color: '#f97316' },
    { label: 'Pending Actions',       value: data.pending_actions,       color: '#eab308' },
    { label: 'High Priority Actions', value: data.high_priority_actions, color: '#ec4899' },
    { label: 'At Risk Projects',      value: data.at_risk_projects,      color: '#14b8a6' },
  ];

  return (
    <div>
      <h2 style={{ fontSize: 24, fontWeight: 700, marginBottom: 24 }}>📊 Dashboard</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: 16, marginBottom: 32 }}>
        {cards.map(c => (
          <div key={c.label} style={{ background: '#1a1d2e', borderRadius: 12, padding: 20, borderLeft: `4px solid ${c.color}` }}>
            <div style={{ fontSize: 32, fontWeight: 700, color: c.color }}>{c.value}</div>
            <div style={{ fontSize: 13, color: '#94a3b8', marginTop: 4 }}>{c.label}</div>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 24 }}>
        <Section title="🚨 Recent Escalations">
          {data.recent_escalations.map(e => (
            <Item key={e.id} title={e.description} sub={`Raised by: ${e.raised_by || 'N/A'} • ${e.severity}`} color="#ef4444" />
          ))}
        </Section>
        <Section title="✅ Pending Action Items">
          {data.pending_action_items.map(a => (
            <Item key={a.id} title={a.description} sub={`Owner: ${a.owner || 'N/A'} • ${a.priority}`} color="#6366f1" />
          ))}
        </Section>
      </div>
    </div>
  );
}

// ─── Ingest ───────────────────────────────────────────────────────────────────
function Ingest() {
  const [title, setTitle]     = useState('');
  const [content, setContent] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult]   = useState(null);
  const [error, setError]     = useState('');
  const fileRef = useRef();

  const ingest = async () => {
    if (!content.trim()) { setError('Content is required'); return; }
    setLoading(true); setError(''); setResult(null);
    try {
      const r = await fetch(`${API}/api/meetings/ingest`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title: title || 'Untitled Meeting', content })
      });
      const d = await r.json();
      if (!r.ok) throw new Error(d.detail || 'Failed');
      setResult(d);
    } catch (e) { setError(e.message); }
    setLoading(false);
  };

  const loadExamples = async () => {
    setLoading(true); setError(''); setResult(null);
    try {
      const r = await fetch(`${API}/api/meetings/example/load`);
      const d = await r.json();
      setResult({ message: `✅ Loaded ${d.loaded} example meetings!`, counts: {} });
    } catch (e) { setError(e.message); }
    setLoading(false);
  };

  // ── FILE UPLOAD FIX ──
  const uploadFile = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setLoading(true); setError(''); setResult(null);
    try {
      const formData = new FormData();
      formData.append('file', file);
      const r = await fetch(`${API}/api/meetings/ingest/file`, {
        method: 'POST',
        body: formData
      });
      const d = await r.json();
      if (!r.ok) throw new Error(d.detail || 'Upload failed');
      setResult(d);
    } catch (e) { setError(e.message); }
    setLoading(false);
    e.target.value = '';
  };

  return (
    <div style={{ maxWidth: 860 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <h2 style={{ fontSize: 24, fontWeight: 700 }}>⚡ Ingest Meeting</h2>
        <div style={{ display: 'flex', gap: 12 }}>
          <button onClick={loadExamples} disabled={loading} style={btnStyle('#6366f1')}>
            📋 Load 3 Example Meetings
          </button>
          {/* Upload button */}
          <button onClick={() => fileRef.current.click()} disabled={loading} style={btnStyle('#0f172a', '#6366f1')}>
            📁 Upload .txt / .md
          </button>
          <input ref={fileRef} type="file" accept=".txt,.md" style={{ display: 'none' }} onChange={uploadFile} />
        </div>
      </div>

      <input value={title} onChange={e => setTitle(e.target.value)} placeholder="Meeting title (optional)"
        style={{ width: '100%', background: '#1a1d2e', border: '1px solid #2d3748', borderRadius: 8, padding: '12px 16px', color: '#e2e8f0', fontSize: 14, marginBottom: 12, boxSizing: 'border-box' }} />

      <textarea value={content} onChange={e => setContent(e.target.value)}
        placeholder="Paste raw meeting transcript, summary, or discussion notes here..."
        style={{ width: '100%', height: 200, background: '#1a1d2e', border: '1px solid #2d3748', borderRadius: 8, padding: '12px 16px', color: '#e2e8f0', fontSize: 14, resize: 'vertical', boxSizing: 'border-box' }} />

      {error && <div style={{ color: '#ef4444', marginTop: 8, fontSize: 14 }}>❌ {error}</div>}

      <button onClick={ingest} disabled={loading} style={{ ...btnStyle('#6366f1'), width: '100%', marginTop: 12, padding: '14px', fontSize: 15 }}>
        {loading ? '⏳ Processing...' : '⚡ Extract Intelligence'}
      </button>

      {result && (
        <div style={{ marginTop: 24, background: '#1a1d2e', borderRadius: 12, padding: 20 }}>
          {result.message ? (
            <p style={{ color: '#22c55e', fontSize: 16 }}>{result.message}</p>
          ) : (
            <>
              <p style={{ color: '#22c55e', marginBottom: 12 }}>✅ Meeting ingested: <b>{result.title}</b></p>
              <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
                {Object.entries(result.counts || {}).map(([k, v]) => (
                  <div key={k} style={{ background: '#0f1117', borderRadius: 8, padding: '8px 16px', fontSize: 13 }}>
                    <b style={{ color: '#a78bfa' }}>{v}</b> {k.replace('_', ' ')}
                  </div>
                ))}
              </div>
            </>
          )}
        </div>
      )}
    </div>
  );
}

// ─── Meetings ─────────────────────────────────────────────────────────────────
function Meetings() {
  const [meetings, setMeetings] = useState([]);
  const [selected, setSelected] = useState(null);

  useEffect(() => { fetch(`${API}/api/meetings`).then(r => r.json()).then(setMeetings); }, []);

  const open = (id) => fetch(`${API}/api/meetings/${id}`).then(r => r.json()).then(setSelected);

  return (
    <div>
      <h2 style={{ fontSize: 24, fontWeight: 700, marginBottom: 24 }}>📅 Meetings ({meetings.length})</h2>
      <div style={{ display: 'grid', gap: 12 }}>
        {meetings.map(m => (
          <div key={m.id} onClick={() => open(m.id)} style={{ background: '#1a1d2e', borderRadius: 10, padding: '16px 20px', cursor: 'pointer', border: '1px solid #2d3748' }}>
            <div style={{ fontWeight: 600 }}>{m.title}</div>
            <div style={{ fontSize: 12, color: '#64748b', marginTop: 4 }}>{new Date(m.created_at).toLocaleString()}</div>
          </div>
        ))}
      </div>

      {selected && (
        <div style={{ marginTop: 24, background: '#1a1d2e', borderRadius: 12, padding: 24 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between' }}>
            <h3 style={{ fontSize: 18, fontWeight: 700 }}>{selected.title}</h3>
            <button onClick={() => setSelected(null)} style={{ background: 'none', border: 'none', color: '#94a3b8', cursor: 'pointer', fontSize: 18 }}>✕</button>
          </div>
          {['action_items','escalations','risks','blockers','decisions','stakeholders'].map(key => (
            selected[key]?.length > 0 && (
              <div key={key} style={{ marginTop: 16 }}>
                <h4 style={{ color: '#a78bfa', marginBottom: 8, textTransform: 'capitalize' }}>{key.replace('_',' ')}</h4>
                {selected[key].map((item, i) => (
                  <div key={i} style={{ background: '#0f1117', borderRadius: 8, padding: '10px 14px', marginBottom: 6, fontSize: 13 }}>
                    {item.description || item.name} {item.owner && <span style={{ color: '#64748b' }}>• {item.owner}</span>}
                  </div>
                ))}
              </div>
            )
          ))}
        </div>
      )}
    </div>
  );
}

