// ─── Query ────────────────────────────────────────────────────────────────────
function QueryPage() {
  const [question, setQuestion] = useState('');
  const [answer, setAnswer]     = useState('');
  const [loading, setLoading]   = useState(false);

  const ask = async () => {
    if (!question.trim()) return;
    setLoading(true); setAnswer('');
    try {
      const r = await fetch(`${API}/api/query`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ question })
      });
      const d = await r.json();
      setAnswer(d.answer);
    } catch (e) { setAnswer('Error: ' + e.message); }
    setLoading(false);
  };

  const examples = [
    'What are the current unresolved escalations?',
    'Which projects are at risk this week?',
    'Show all pending tasks assigned to Rahul.',
    'List all high-priority blockers across teams.',
  ];

  return (
    <div style={{ maxWidth: 800 }}>
      <h2 style={{ fontSize: 24, fontWeight: 700, marginBottom: 24 }}>🔍 Query Intelligence</h2>
      <div style={{ display: 'flex', gap: 10, marginBottom: 16, flexWrap: 'wrap' }}>
        {examples.map(q => (
          <button key={q} onClick={() => setQuestion(q)} style={{ background: '#1a1d2e', border: '1px solid #2d3748', borderRadius: 20, padding: '6px 14px', color: '#a78bfa', cursor: 'pointer', fontSize: 12 }}>{q}</button>
        ))}
      </div>
      <div style={{ display: 'flex', gap: 10 }}>
        <input value={question} onChange={e => setQuestion(e.target.value)} onKeyDown={e => e.key === 'Enter' && ask()}
          placeholder="Ask anything about your meetings..."
          style={{ flex: 1, background: '#1a1d2e', border: '1px solid #2d3748', borderRadius: 8, padding: '12px 16px', color: '#e2e8f0', fontSize: 14 }} />
        <button onClick={ask} disabled={loading} style={btnStyle('#6366f1')}>
          {loading ? '⏳' : '🔍 Ask'}
        </button>
      </div>
      {answer && (
        <div style={{ marginTop: 20, background: '#1a1d2e', borderRadius: 12, padding: 20, lineHeight: 1.7, fontSize: 14, whiteSpace: 'pre-wrap' }}>
          {answer}
        </div>
      )}
    </div>
  );
}

// ─── Helpers ──────────────────────────────────────────────────────────────────
function Loader() {
  return <div style={{ color: '#64748b', padding: 32, textAlign: 'center' }}>Loading...</div>;
}

function Section({ title, children }) {
  return (
    <div style={{ background: '#1a1d2e', borderRadius: 12, padding: 20 }}>
      <h3 style={{ fontSize: 16, fontWeight: 600, marginBottom: 14 }}>{title}</h3>
      {children}
    </div>
  );
}

function Item({ title, sub, color }) {
  return (
    <div style={{ borderLeft: `3px solid ${color}`, paddingLeft: 12, marginBottom: 10 }}>
      <div style={{ fontSize: 13 }}>{title}</div>
      <div style={{ fontSize: 11, color: '#64748b', marginTop: 2 }}>{sub}</div>
    </div>
  );
}

function btnStyle(bg, border) {
  return {
    background: bg, border: border ? `1px solid ${border}` : 'none',
    borderRadius: 8, padding: '10px 18px', color: '#fff', cursor: 'pointer', fontSize: 14, fontWeight: 500
  };
}
